// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ProcurementAcceptance) predicate.ProcurementAcceptance {
	return predicate.ProcurementAcceptance(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ProcurementAcceptance) predicate.ProcurementAcceptance {
	return predicate.ProcurementAcceptance(sql.NotPredicates(p))
}
